// Enable the plugin
core.setStelProperty("ArchaeoLines.enabled", true);

// Check if enabled
var isEnabled = core.getStelProperty("ArchaeoLines.enabled");
//Show response on stellarium Help:log
console.log("ArchaeoLines enabled:", isEnabled);
//Show response on debug log
core.debug("ArchaeoLines enabled:" + isEnabled);

// Change equinox color to cyan
var cyan = core.vec3f(0.0, 0.8, 0.9);
ArchaeoLines.setEquinoxColor(cyan);

// Read current color
var colorStr = core.getStelProperty("ArchaeoLines.equinoxColor");
console.log("Current equinox color:", colorStr);

// Change solstice colors to red
var red = core.vec3f(1.0, 0.2, 0.2);
ArchaeoLines.setSolsticesColor(red);

// Change Sun's line color to yellow
var yellow = core.vec3f(1.0, 1.0, 0.0);
ArchaeoLines.setCurrentSunColor(yellow);

// Set equinox line to bright green
var green = core.vec3f(0.2, 0.9, 0.2);
ArchaeoLines.setEquinoxColor(green);
